import type {
  SchemePartialOptions,
  SchemeCheck,
  HTTPRequest,
  HTTPResponse,
  TokenableScheme
} from '../types'
import type { Auth } from '../core'
import { LocalScheme, LocalSchemeEndpoints, LocalSchemeOptions } from './local'

export interface CookieSchemeEndpoints extends LocalSchemeEndpoints {
  csrf: HTTPRequest
}

export interface CookieSchemeCookie {
  name: string
}

export interface CookieSchemeOptions extends LocalSchemeOptions {
  endpoints: CookieSchemeEndpoints
  cookie: CookieSchemeCookie
}

const DEFAULTS: SchemePartialOptions<CookieSchemeOptions> = {
  name: 'cookie',
  cookie: {
    name: null
  },
  token: {
    type: '',
    property: '',
    maxAge: false,
    global: false,
    required: false
  },
  endpoints: {
    csrf: null
  }
}

export class CookieScheme<
    OptionsT extends CookieSchemeOptions = CookieSchemeOptions
  >
  extends LocalScheme<OptionsT>
  implements TokenableScheme<OptionsT>
{
  constructor($auth: Auth, options: SchemePartialOptions<CookieSchemeOptions>) {
    super($auth, options, DEFAULTS)
  }

  mounted(): Promise<HTTPResponse | void> {
    if (process.server) {
      this.$auth.ctx.$axios.setHeader(
        'referer',
        this.$auth.ctx.req.headers.host
      )
    }

    return super.mounted()
  }

  check(): SchemeCheck {
    const response = { valid: false }

    if (!super.check().valid) {
      return response
    }

    if (this.options.cookie.name) {
      const cookies = this.$auth.$storage.getCookies()
      response.valid = Boolean(cookies[this.options.cookie.name])
      return response
    }

    response.valid = true
    return response
  }

  async login(endpoint: HTTPRequest): Promise<HTTPResponse> {
    // Ditch any leftover local tokens before attempting to log in
    this.$auth.reset()

    // Make CSRF request if required
    if (this.options.endpoints.csrf) {
      await this.$auth.request(this.options.endpoints.csrf, {
        maxRedirects: 0
      })
    }

    return super.login(endpoint, { reset: false })
  }

  reset(): void {
    if (this.options.cookie.name) {
      this.$auth.$storage.setCookie(this.options.cookie.name, null, {
        prefix: ''
      })
    }

    return super.reset()
  }
}

import type { Raw } from 'vue'
import type { GuideMeta, PlaygroundFeatures } from '~/types/guides'

const defaultFeatures = Object.freeze(<PlaygroundFeatures>{
  fileTree: false,
  terminal: false,
  navigation: true,
  download: true,
})

export const useGuideStore = defineStore('guide', () => {
  const play = usePlaygroundStore()
  const ui = useUiState()
  const preview = usePreviewStore()

  const features = ref<PlaygroundFeatures>(defaultFeatures)
  const currentGuide = shallowRef<Raw<GuideMeta>>()
  const showingSolution = ref(false)
  const embeddedDocs = ref('')

  const ignoredFiles = computed(() => transformGuideIgnoredFiles(currentGuide.value?.ignoredFiles))

  watch(features, () => {
    if (features.value.fileTree === true) {
      if (ui.panelFileTree <= 0)
        ui.panelFileTree = 20
    }
    else if (features.value.fileTree === false) {
      ui.panelFileTree = 0
    }

    if (features.value.terminal === true)
      ui.showTerminal = true
    else if (features.value.terminal === false)
      ui.showTerminal = false
  })

  async function mount(guide?: GuideMeta, withSolution = false) {
    await play.init

    // eslint-disable-next-line no-console
    console.log('mounting guide', guide)

    await play.mount({
      ...guide?.files,
      ...withSolution ? guide?.solutions : {},
    })

    play.fileSelected = play.files.get(guide?.startingFile || 'app.vue')
    preview.location.fullPath = guide?.startingUrl || '/'
    preview.updateUrl()

    features.value = {
      ...defaultFeatures,
      ...guide?.features,
    }
    currentGuide.value = guide
    showingSolution.value = withSolution

    return undefined
  }

  async function toggleSolutions() {
    await mount(currentGuide.value, !showingSolution.value)
  }

  function openEmbeddedDocs(url: string) {
    embeddedDocs.value = url
  }

  return {
    mount,
    toggleSolutions,
    features,
    currentGuide,
    showingSolution,
    embeddedDocs,
    openEmbeddedDocs,
    ignoredFiles,
  }
})

if (import.meta.hot)
  import.meta.hot.accept(acceptHMRUpdate(useGuideStore, import.meta.hot))

import { existsSync, promises as fsp } from 'node:fs'
import { resolve } from 'pathe'
import { defineCommand } from 'citty'
import { consola } from 'consola'
import { splitByCase, upperFirst, camelCase, kebabCase } from 'scule'
import { appendFile, appendThemeDefault, sortFile } from '../../utils.mjs'
import templates from '../../templates.mjs'

export default defineCommand({
  meta: {
    name: 'component',
    description: 'Make a new component.'
  },
  args: {
    name: {
      type: 'positional',
      required: true,
      description: 'Name of the component.'
    },
    primitive: {
      type: 'boolean',
      description: 'Create a primitive component.'
    },
    prose: {
      type: 'boolean',
      description: 'Create a prose component.'
    },
    content: {
      type: 'boolean',
      description: 'Create a content component.'
    },
    template: {
      type: 'string',
      description: 'Only generate template.'
    }
  },
  async setup({ args }) {
    const name = args.name
    if (!name) {
      consola.error('`name` argument is missing!')
      process.exit(1)
    }

    const path = resolve('.')

    for (const template of Object.keys(templates)) {
      if (args.template && template !== args.template) {
        continue
      }

      const { filename, contents } = templates[template](args)
      if (!contents) {
        continue
      }

      const filePath = resolve(path, filename)

      if (existsSync(filePath)) {
        consola.error(`🚨 ${filePath} already exists!`)
        continue
      }

      await fsp.writeFile(filePath, contents.trim() + '\n')

      consola.success(`🪄 Generated ${filePath}!`)
    }

    if (args.template) {
      return
    }

    const themePath = resolve(path, `src/theme/${args.prose ? 'prose/' : ''}${args.content ? 'content/' : ''}index.ts`)
    await appendFile(themePath, `export { default as ${camelCase(name)} } from './${kebabCase(name)}'`)
    await sortFile(themePath)

    if (!args.prose) {
      const typesPath = resolve(path, 'src/runtime/types/index.ts')
      const pascal = splitByCase(name).map(p => upperFirst(p)).join('')
      await appendFile(typesPath, `export * from '../components/${args.content ? 'content/' : ''}${pascal}.vue'`)
      await sortFile(typesPath)

      const useComponentPropsPath = resolve(path, 'src/runtime/composables/useComponentProps.ts')
      await appendThemeDefault(useComponentPropsPath, camelCase(name), `${pascal}Props`)
    }
  }
})

import { consola } from "consola";
import { Hookable, createDebugger } from "hookable";
import type { LoadConfigOptions, Nitro, NitroConfig, NitroDynamicConfig } from "nitro/types";
import { version as nitroVersion } from "nitro/meta";
import { loadOptions } from "./config/loader.ts";
import { updateNitroConfig } from "./config/update.ts";
import { installModules } from "./module.ts";
import { scanAndSyncOptions, scanHandlers } from "./scan.ts";
import { initNitroRouting } from "./routing.ts";
import { registerNitroInstance } from "./global.ts";

export async function createNitro(
  config: NitroConfig = {},
  opts: LoadConfigOptions = {}
): Promise<Nitro> {
  // Resolve options
  const options = await loadOptions(config, opts);

  // Create nitro context
  const nitro: Nitro = {
    meta: {
      version: nitroVersion,
      majorVersion: 3,
    },
    options,
    hooks: new Hookable(),
    vfs: new Map(),
    routing: {} as any,
    logger: consola.withTag("nitro"),
    scannedHandlers: [],
    fetch: () => {
      throw new Error("no dev server attached!");
    },
    close: () => Promise.resolve(nitro.hooks.callHook("close")),
    async updateConfig(config: NitroDynamicConfig) {
      updateNitroConfig(nitro, config);
    },
  };

  // Global setup
  registerNitroInstance(nitro);

  // Init routers
  initNitroRouting(nitro);

  // Scan dirs (plugins, tasks, modules) and sync options
  // TODO: Make it side-effect free to allow proper watching
  await scanAndSyncOptions(nitro);

  // Debug
  if (nitro.options.debug) {
    createDebugger(nitro.hooks, { tag: "nitro" });
  }

  // Logger
  if (nitro.options.logLevel !== undefined) {
    nitro.logger.level = nitro.options.logLevel;
  }

  // Hooks
  nitro.hooks.addHooks(nitro.options.hooks);

  // Scan and install modules
  await installModules(nitro);

  // Auto imports
  if (nitro.options.imports) {
    // Create unimport instance
    const { createUnimport } = await import("unimport");
    nitro.unimport = createUnimport(nitro.options.imports);
    await nitro.unimport.init();
    // Support for importing from '#imports'
    nitro.options.virtual["#imports"] = () => nitro.unimport?.toExports() || "";
    // Backward compatibility
    nitro.options.virtual["#nitro"] = 'export * from "#imports"';
  }

  // Ensure initial handlers are populated
  await scanHandlers(nitro);

  // Sync routers
  nitro.routing.sync();

  return nitro;
}

import { useDevtoolsClient } from '@nuxt/devtools-kit/iframe-client'
import { openElementSourceComponent } from './vue-tracer'

let overlay: HTMLDivElement | null = null

// Get the parent window where the actual app is running
function getTargetWindow() {
  try {
    // The devtools client iframe structure is: parent -> devtools iframe -> client iframe
    // We need to access the parent window (the actual app window)
    return window.parent?.parent || window.parent || window
  }
  catch {
    return window
  }
}

function createOverlay() {
  if (overlay)
    return overlay

  const targetWindow = getTargetWindow()
  const targetDocument = targetWindow.document

  overlay = targetDocument.createElement('div')
  overlay.style.cssText = `
    position: absolute;
    pointer-events: none;
    z-index: 999999;
    background: rgba(104, 182, 255, 0.3);
    border: 2px solid rgb(104, 182, 255);
    border-radius: 4px;
    transition: all 0.1s ease;
  `
  targetDocument.body.appendChild(overlay)
  return overlay
}

function removeOverlay() {
  if (overlay) {
    overlay.remove()
    overlay = null
  }
}

export function useElementHighlighter() {
  const client = useDevtoolsClient()

  const highlightElement = (element: HTMLElement | undefined) => {
    if (!element) {
      removeOverlay()
      return
    }

    const targetWindow = getTargetWindow()
    const rect = element.getBoundingClientRect()
    const overlayEl = createOverlay()

    // Account for scroll position in the target window
    overlayEl.style.left = `${rect.left + targetWindow.scrollX}px`
    overlayEl.style.top = `${rect.top + targetWindow.scrollY}px`
    overlayEl.style.width = `${rect.width}px`
    overlayEl.style.height = `${rect.height}px`
    overlayEl.style.display = 'block'
  }

  const clearHighlight = () => {
    if (overlay) {
      overlay.style.display = 'none'
    }
  }

  const inspectElementInEditor = async (element: HTMLElement | undefined) => {
    if (!element)
      return

    const clientValue = client.value
    if (!clientValue)
      return

    // Use devtools inspector to open element in editor
    try {
      // Prefer Nuxt tracer to resolve the component file and open it in editor
      openElementSourceComponent(element)
    }
    catch (error) {
      console.warn('Failed to inspect element:', error)
    }
  }

  return {
    highlightElement,
    clearHighlight,
    inspectElementInEditor,
  }
}

import type { SitemapWarning } from './parseSitemapXml'

export interface SitemapIndexEntry {
  loc: string
  lastmod?: string
}

export interface SitemapIndexParseResult {
  entries: SitemapIndexEntry[]
  warnings: SitemapWarning[]
}

interface ParsedSitemap {
  loc?: string
  lastmod?: string
}

interface ParsedSitemapIndex {
  sitemap?: ParsedSitemap | ParsedSitemap[]
}

interface ParsedRoot {
  sitemapindex?: ParsedSitemapIndex
}

function isValidUrl(value: string): boolean {
  return URL.canParse(value)
}

export async function parseSitemapIndex(xml: string): Promise<SitemapIndexParseResult> {
  if (!xml)
    throw new Error('Empty XML input provided')

  const { XMLParser } = await import('fast-xml-parser')
  const parser = new XMLParser({
    isArray: (tagName: string) => tagName === 'sitemap',
    removeNSPrefix: true,
    trimValues: true,
  })
  const parsed = parser.parse(xml) as ParsedRoot

  if (parsed?.sitemapindex === undefined)
    throw new Error('XML does not contain a valid sitemapindex element')

  if (!parsed.sitemapindex || !parsed.sitemapindex.sitemap)
    return { entries: [], warnings: [] }

  const sitemaps = Array.isArray(parsed.sitemapindex.sitemap)
    ? parsed.sitemapindex.sitemap
    : [parsed.sitemapindex.sitemap]

  const warnings: SitemapWarning[] = []
  const entries: SitemapIndexEntry[] = []

  for (const s of sitemaps) {
    if (typeof s.loc !== 'string' || !s.loc.trim().length) {
      warnings.push({
        type: 'validation',
        message: 'Sitemap entry missing required loc element',
      })
      continue
    }
    const loc = s.loc.trim()
    if (!isValidUrl(loc)) {
      warnings.push({
        type: 'validation',
        message: 'Sitemap entry has invalid URL',
        context: { url: loc },
      })
      continue
    }
    entries.push({
      loc,
      ...(s.lastmod && { lastmod: s.lastmod.trim() }),
    })
  }

  return { entries, warnings }
}

export function isSitemapIndex(xml: string): boolean {
  return xml.includes('<sitemapindex') || xml.includes('sitemapindex>')
}

import type { StrapiFilterRequestParam, StrapiLocale, StrapiRequestParamField, StrapiRequestParamPopulate, StrapiRequestParamSort } from '.'

export interface Strapi4Error {
  error: {
    status: number
    name: string
    message: string
    details: Record<string, unknown>
  }
}

export interface PaginationByPage {
  page: number
  pageSize: number
  withCount?: boolean
}

export interface PaginationByOffset {
  start: number
  limit: number
  withCount?: boolean
}

export interface Strapi4RequestParams<T> {
  fields?: Array<StrapiRequestParamField<T>>
  populate?: Strapi4RequestPopulateParam<T>
  sort?: StrapiRequestParamSort<T> | Array<StrapiRequestParamSort<T>>
  pagination?: PaginationByOffset | PaginationByPage
  filters?: StrapiFilterRequestParam<T>
  publicationState?: 'live' | 'preview'
  locale?: StrapiLocale
}

export type Strapi4RequestPopulateParams<T> = Pick<Strapi4RequestParams<T>, 'fields' | 'sort' | 'populate' | 'filters'>

// Unified type for Strapi populate, combining both string paths and nested objects.
export type Strapi4RequestPopulateParam<T>
  = | '*' // Populate all relations.
    | { [K in keyof T]?: // Nested object population.
      T[K] extends object
        ? T[K] extends Array<infer I>
          ? Strapi4RequestPopulateParam<I> | Strapi4RequestPopulateParams<I>
          : Strapi4RequestPopulateParam<T[K]> | Strapi4RequestPopulateParams<T[K]>
        : never
    }
    | StrapiRequestParamPopulate<T> // String paths like "field.subfield".
    | Array<StrapiRequestParamPopulate<T>> // Array of string paths.

export interface Strapi4ResponseData<T> {
  id: number
  attributes: T
  meta: Record<string, unknown>
}

export interface Strapi4Response<T> {
  data: Strapi4ResponseData<T> | Strapi4ResponseData<T>[]
  meta: Strapi4ResponseMeta
}

export interface Strapi4ResponseSingle<T> {
  data: Strapi4ResponseData<T>
  meta: Strapi4ResponseMeta
}

export interface Strapi4ResponseMany<T> {
  data: Strapi4ResponseData<T>[]
  meta: Strapi4ResponseMeta
}

export interface Strapi4ResponseMeta {
  pagination: MetaResponsePaginationByPage | MetaResponsePaginationByOffset
  [key: string]: unknown
}

export interface MetaResponsePaginationByPage {
  page: number
  pageSize: number
  pageCount: number
  total: number
}

export interface MetaResponsePaginationByOffset {
  start: number
  limit: number
  total: number
}

import type { ArgsDef, CommandDef } from 'citty'
import tab from '@bomb.sh/tab/citty'
import { nitroPresets } from './data/nitro-presets'
import { templates } from './data/templates'

export async function initCompletions<T extends ArgsDef = ArgsDef>(command: CommandDef<T>) {
  const completion = await tab(command)

  const devCommand = completion.commands.get('dev')
  if (devCommand) {
    const portOption = devCommand.options.get('port')
    if (portOption) {
      portOption.handler = (complete) => {
        complete('3000', 'Default development port')
        complete('3001', 'Alternative port')
        complete('8080', 'Common alternative port')
      }
    }

    const hostOption = devCommand.options.get('host')
    if (hostOption) {
      hostOption.handler = (complete) => {
        complete('localhost', 'Local development')
        complete('0.0.0.0', 'Listen on all interfaces')
        complete('127.0.0.1', 'Loopback address')
      }
    }
  }

  const buildCommand = completion.commands.get('build')
  if (buildCommand) {
    const presetOption = buildCommand.options.get('preset')
    if (presetOption) {
      presetOption.handler = (complete) => {
        for (const preset of nitroPresets) {
          complete(preset, '')
        }
      }
    }
  }

  const initCommand = completion.commands.get('init')
  if (initCommand) {
    const templateOption = initCommand.options.get('template')
    if (templateOption) {
      templateOption.handler = (complete) => {
        for (const template in templates) {
          complete(template, templates[template as 'content']?.description || '')
        }
      }
    }
  }

  const addCommand = completion.commands.get('add')
  if (addCommand) {
    const cwdOption = addCommand.options.get('cwd')
    if (cwdOption) {
      cwdOption.handler = (complete) => {
        complete('.', 'Current directory')
      }
    }
  }

  const logLevelCommands = ['dev', 'build', 'generate', 'preview', 'prepare', 'init']
  for (const cmdName of logLevelCommands) {
    const cmd = completion.commands.get(cmdName)
    if (cmd) {
      const logLevelOption = cmd.options.get('logLevel')
      if (logLevelOption) {
        logLevelOption.handler = (complete) => {
          complete('silent', 'No logs')
          complete('info', 'Standard logging')
          complete('verbose', 'Detailed logging')
        }
      }
    }
  }

  return completion
}

